package java_sample_project;

public class Switchdress {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int size=28;
		switch(size) {
		case 28:System.out.println("small");
		break;
		case 30:System.out.println("medium");
		break;
		case 32:System.out.println("large");
		break;
		case 34:System.out.println("xl");
		break;
		case 36:System.out.println("xxl");
		break;
		default:System.out.println("invalid");
		
		}

	}

}
